package storage

import (
	"context"
	"errors"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/bson"
	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"

	"github.com/utilitywarehouse/telecom-mobile/pkg/handsetdb"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/terrors"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tstorage/tmongo"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/models"
)

//go:generate mockgen -destination=./mocks/$GOFILE -source=./$GOFILE

type MongoCollection interface {
	InsertOne(ctx context.Context, document any, opts ...*options.InsertOneOptions) (*mongo.InsertOneResult, error)
	UpdateOne(ctx context.Context, filter any, update any, opts ...*options.UpdateOptions) (*mongo.UpdateResult, error)
	FindOne(ctx context.Context, filter any, opts ...*options.FindOneOptions) *mongo.SingleResult
	Find(ctx context.Context, filter any, opts ...*options.FindOptions) (cur *mongo.Cursor, err error)
}

const (
	collectionHandsets  = "handsets"
	collectionContracts = "contracts"
)

type storage struct {
	tmongo.Mongo
	handsetsCollection  MongoCollection
	contractsCollection MongoCollection
	nowFunc             func() time.Time
}

func NewStorage(ctx context.Context, mongo tmongo.Mongo, nowFunc func() time.Time) (*storage, error) {
	db := &storage{
		Mongo:               mongo,
		handsetsCollection:  mongo.Client.Database(mongo.Database).Collection(collectionHandsets),
		contractsCollection: mongo.Client.Database(mongo.Database).Collection(collectionContracts),
		nowFunc:             nowFunc,
	}

	err := db.ensureIndexes(ctx, mongo)
	if err != nil {
		return nil, err
	}

	return db, nil
}

func (s storage) ensureIndexes(ctx context.Context, mongoDb tmongo.Mongo) error {
	err := tmongo.CreateIndexes(ctx, mongoDb, tmongo.CollectionIndexesMap{
		collectionHandsets: {
			mongo.IndexModel{
				Keys:    bson.M{"id": 1},
				Options: options.Index().SetName("id").SetUnique(true),
			},
		},
		collectionContracts: {
			mongo.IndexModel{
				Keys:    bson.M{"id": 1},
				Options: options.Index().SetName("contract_id").SetUnique(true),
			},
			mongo.IndexModel{
				Keys:    bson.M{"requestId": 1},
				Options: options.Index().SetName("contract_request_id").SetUnique(true),
			},
			mongo.IndexModel{
				Keys:    bson.M{"serviceId": 1},
				Options: options.Index().SetName("contract_service_id"),
			},
		},
	})()

	return err
}

func (s storage) UpsertHandset(ctx context.Context, handset handsetdb.Handset) error {
	m := bson.M{
		"id": handset.ID,
	}

	if handset.Name != "" {
		m["name"] = handset.Name
	}

	if handset.RetailPrice != "" {
		m["retailPrice"] = handset.RetailPrice
	}

	if handset.ContractPrice != "" {
		m["contractPrice"] = handset.ContractPrice
	}

	if handset.ContractTerm != "" {
		m["contractTerm"] = handset.ContractTerm
	}

	m["active"] = handset.Active
	m["outOfStock"] = handset.OutOfStock

	set := bson.M{
		"$set": m,
	}

	_, err := s.handsetsCollection.
		UpdateOne(ctx, bson.M{"id": handset.ID}, set, options.Update().SetUpsert(true))
	if err != nil {
		return fmt.Errorf("could not upsert handset: %w", err)
	}

	return nil
}

func (s storage) GetHandsets(ctx context.Context, isInStock bool) ([]handsetdb.Handset, error) {
	filter := bson.M{"outOfStock": !isInStock}

	cur, err := s.handsetsCollection.Find(ctx, filter)
	if err != nil {
		return nil, fmt.Errorf("could not find handsets: %w", err)
	}

	defer func(cur *mongo.Cursor, ctx context.Context) {
		err := cur.Close(ctx)
		if err != nil {
			tlog.Error(ctx, "could not close cursor: %s", err.Error())
		}
	}(cur, ctx)

	var handsets []handsetdb.Handset
	for cur.Next(ctx) {
		var handset handsetdb.Handset
		err := cur.Decode(&handset)
		if err != nil {
			return nil, fmt.Errorf("could not decode handset: %w", err)
		}
		handsets = append(handsets, handset)
	}

	if err := cur.Err(); err != nil {
		return nil, fmt.Errorf("error iterating over handsets: %w", err)
	}

	return handsets, nil
}

func (s storage) GetHandsetByID(ctx context.Context, handsetID string) (*handsetdb.Handset, error) {
	var h handsetdb.Handset
	err := s.handsetsCollection.FindOne(ctx, bson.M{"id": handsetID}).Decode(&h)
	if err != nil {
		if errors.Is(err, mongo.ErrNoDocuments) {
			return nil, terrors.ErrNotFound
		}
		return nil, fmt.Errorf("could not find handset by id: %w", err)
	}
	return &h, nil
}

func (s storage) CreateContract(ctx context.Context, contract models.Contract) error {
	_, err := s.contractsCollection.InsertOne(ctx, contract)
	if err != nil {
		return fmt.Errorf("could not create contract: %w", err)
	}
	return nil
}

func (s storage) GetContractByRequestID(ctx context.Context, requestID string) (*models.Contract, error) {
	var contract models.Contract
	err := s.contractsCollection.FindOne(ctx, bson.M{"requestId": requestID}).Decode(&contract)
	if err != nil {
		if errors.Is(err, mongo.ErrNoDocuments) {
			return nil, terrors.ErrNotFound
		}
		return nil, fmt.Errorf("could not find contract by request id: %w", err)
	}
	return &contract, nil
}

func (s storage) GetContractByID(ctx context.Context, contractID string) (*models.Contract, error) {
	var contract models.Contract
	err := s.contractsCollection.FindOne(ctx, bson.M{"id": contractID}).Decode(&contract)
	if err != nil {
		if errors.Is(err, mongo.ErrNoDocuments) {
			return nil, terrors.ErrNotFound
		}
		return nil, fmt.Errorf("could not find contract by id: %w", err)
	}
	return &contract, nil
}

func (s storage) GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error) {
	activeStatuses := bson.A{
		models.ContractStatusPendingEligibility,
		models.ContractStatusEligibilityApproved,
		models.ContractStatusApproved,
		models.ContractStatusHandsetOrdered,
	}
	filter := bson.M{
		"serviceId": serviceID,
		"status":    bson.M{"$in": activeStatuses},
	}

	var contract models.Contract
	err := s.contractsCollection.FindOne(ctx, filter).Decode(&contract)
	if err != nil {
		if errors.Is(err, mongo.ErrNoDocuments) {
			return nil, terrors.ErrNotFound
		}
		return nil, fmt.Errorf("could not find active contract for service: %w", err)
	}
	return &contract, nil
}

func (s storage) UpdateContractStatus(ctx context.Context, requestID string, status models.ContractStatus) error {
	filter := bson.M{"requestId": requestID}
	return s.updateContractStatus(ctx, filter, status, expectedCurrentStatuses(status)...)
}

func (s storage) UpdateContractStatusByID(ctx context.Context, contractID string, status models.ContractStatus) error {
	filter := bson.M{"id": contractID}
	return s.updateContractStatus(ctx, filter, status, expectedCurrentStatuses(status)...)
}

func expectedCurrentStatuses(status models.ContractStatus) []models.ContractStatus {
	switch status {
	case models.ContractStatusEligibilityApproved, models.ContractStatusDeclined:
		return []models.ContractStatus{models.ContractStatusPendingEligibility}
	case models.ContractStatusApproved:
		return []models.ContractStatus{models.ContractStatusEligibilityApproved}
	case models.ContractStatusHandsetOrdered:
		return []models.ContractStatus{models.ContractStatusApproved}
	default:
		return nil
	}
}

func (s storage) updateContractStatus(ctx context.Context, filter bson.M, status models.ContractStatus, currentStatuses ...models.ContractStatus) error {
	if len(currentStatuses) == 1 {
		filter["status"] = currentStatuses[0]
	} else if len(currentStatuses) > 1 {
		filter["status"] = bson.M{"$in": currentStatuses}
	}
	update := bson.M{
		"$set": bson.M{
			"status":    status,
			"updatedAt": time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract status: %w", err)
	}
	if result.MatchedCount == 0 {
		if len(currentStatuses) > 0 {
			return terrors.ErrConflict
		}
		return terrors.ErrNotFound
	}
	return nil
}

func (s storage) UpdateContractLoanReference(ctx context.Context, requestID string, loanReference string) error {
	filter := bson.M{"requestId": requestID}
	update := bson.M{
		"$set": bson.M{
			"loanReference": loanReference,
			"updatedAt":     time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract loan reference: %w", err)
	}
	if result.MatchedCount == 0 {
		return terrors.ErrNotFound
	}
	return nil
}

func (s storage) UpdateContractBankDetails(ctx context.Context, requestID string, bankAccountNumber string, bankTitle string) error {
	filter := bson.M{"requestId": requestID}
	update := bson.M{
		"$set": bson.M{
			"bankAccountNumber": bankAccountNumber,
			"bankTitle":         bankTitle,
			"updatedAt":         time.Now(),
		},
	}

	result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
	if err != nil {
		return fmt.Errorf("could not update contract bank details: %w", err)
	}
	if result.MatchedCount == 0 {
		return terrors.ErrNotFound
	}
	return nil
}

func (s storage) CustomerHasDeclinedContract(ctx context.Context, customerID string, since time.Duration) (bool, error) {
	filter := bson.M{
		"customerId": customerID,
		"status":     models.ContractStatusDeclined,
		"createdAt":  bson.M{"$gte": s.nowFunc().Add(-since)},
	}

	var contract models.Contract
	err := s.contractsCollection.FindOne(ctx, filter).Decode(&contract)
	if err != nil {
		if errors.Is(err, mongo.ErrNoDocuments) {
			return false, nil
		}
		return false, fmt.Errorf("could not check for declined contract: %w", err)
	}
	return true, nil
}

// StorageWrapper is an exported type that wraps the internal storage struct,
// allowing tests to inject mock collections without needing a real MongoDB connection.
type StorageWrapper struct {
	storage
}

// NewStorageWithCollections creates a StorageWrapper with the given collections injected.
// Intended for use in tests.
func NewStorageWithCollections(handsetsCollection, contractsCollection MongoCollection) *StorageWrapper {
	return &StorageWrapper{
		storage: storage{
			handsetsCollection:  handsetsCollection,
			contractsCollection: contractsCollection,
		},
	}
}

